dslRule:
/*!id: jdt.internal.bindingresolver.remove-bogus-subarray*/
/*!description: Removes redundant CharOperation.subarray(array, 0, array.length) calls which are equivalent to using the array directly, improving clarity and efficiency.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring, performance*/
org.eclipse.jdt.internal.compiler.util.CharOperation.subarray($array, 0, $array.length)
=> $array
;;

/*!id: jdt.internal.bindingresolver.isstatic-to-modifiers-localvar-subarray*/
/*!description: Replaces the 'isStatic' boolean local variable and removes the bogus CharOperation.subarray() call in Scope.getImport, modernizing API usage to 'importReference.modifiers'.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
this.scope.getImport(org.eclipse.jdt.internal.compiler.util.CharOperation.subarray($importReference.tokens, 0, $importReference.tokens.length), true, isStatic)
=> this.scope.getImport($importReference.tokens, true, $importReference.modifiers)
;;

/*!id: jdt.internal.bindingresolver.isstatic-to-modifiers-localvar*/
/*!description: Replaces the 'isStatic' boolean local variable with 'importReference.modifiers' in Scope.getImport method calls, reflecting internal API modernization.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
this.scope.getImport($importReference.tokens, false, isStatic)
=> this.scope.getImport($importReference.tokens, false, $importReference.modifiers)
;;

/*!id: jdt.internal.bindingresolver.isstatic-methodcall-to-modifiers*/
/*!description: Replaces 'importReference.isStatic()' method call with 'importReference.modifiers' field in Scope.getImport calls, reflecting internal API modernization from boolean flag to int bitmask.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
org.eclipse.jdt.internal.compiler.lookup.Scope.getImport($tokens, $onDemand, $importReference.isStatic())
=> org.eclipse.jdt.internal.compiler.lookup.Scope.getImport($tokens, $onDemand, $importReference.modifiers)
;;
